import{_ as e,o as i,c as l,ae as t}from"./chunks/framework.jfJLTIcL.js";const k=JSON.parse('{"title":"局域网部署","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/lan-deployment.md","filePath":"zh-CN/lan-deployment.md","lastUpdated":1776436535000}'),s={name:"zh-CN/lan-deployment.md"};function o(n,a,h,d,r,p){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="局域网部署" tabindex="-1">局域网部署 <a class="header-anchor" href="#局域网部署" aria-label="Permalink to &quot;局域网部署&quot;">​</a></h1><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>让一台机器运行 VILab，局域网内其他机器调用它的 <code>/v1/*</code> 接口。</p><h2 id="推荐方式" tabindex="-1">推荐方式 <a class="header-anchor" href="#推荐方式" aria-label="Permalink to &quot;推荐方式&quot;">​</a></h2><ul><li>一台机器运行 VILab 桌面宿主</li><li>这台机器负责管理 Provider 与 external API key</li><li>其他内部应用使用各自独立的 external API key</li></ul><h2 id="把服务绑定到局域网" tabindex="-1">把服务绑定到局域网 <a class="header-anchor" href="#把服务绑定到局域网" aria-label="Permalink to &quot;把服务绑定到局域网&quot;">​</a></h2><p>内嵌服务会绑定到 <strong>Server URL</strong> 里的主机和端口。</p><p>宿主机推荐配置：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://0.0.0.0:9876</span></span></code></pre></div><p>客户端访问时请使用宿主机的真实局域网 IP 或主机名，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.1.24:9876</span></span></code></pre></div><h2 id="防火墙与可达性" tabindex="-1">防火墙与可达性 <a class="header-anchor" href="#防火墙与可达性" aria-label="Permalink to &quot;防火墙与可达性&quot;">​</a></h2><ul><li>放行服务端口的入站 TCP 流量</li><li>确认局域网其他机器可以访问宿主机 IP</li><li>只在可信内网开放该服务</li></ul><h2 id="在另一台机器上检查健康状态" tabindex="-1">在另一台机器上检查健康状态 <a class="header-anchor" href="#在另一台机器上检查健康状态" aria-label="Permalink to &quot;在另一台机器上检查健康状态&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9876</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">health</span></span></code></pre></div><h2 id="鉴权模型" tabindex="-1">鉴权模型 <a class="header-anchor" href="#鉴权模型" aria-label="Permalink to &quot;鉴权模型&quot;">​</a></h2><ul><li><code>/health</code> 不需要 API key</li><li><code>/v1/*</code> 需要 <code>Authorization: Bearer &lt;external_api_key&gt;</code></li><li><code>/admin/*</code> 需要 <code>Authorization: Bearer &lt;adminKey&gt;</code></li></ul><p>当前实现里 <code>adminKey</code> 仍可访问 public 接口，但这不是推荐用法。正常集成请只发 external API key。</p><h2 id="key-签发规则" tabindex="-1">Key 签发规则 <a class="header-anchor" href="#key-签发规则" aria-label="Permalink to &quot;Key 签发规则&quot;">​</a></h2><p>建议按以下粒度分别签发：</p><ul><li>项目</li><li>脚本</li><li>设备</li><li>集成方</li></ul><p>推荐命名：</p><ul><li><code>web-dashboard-prod</code></li><li><code>ios-prototype-lab</code></li><li><code>robot-gateway-01</code></li></ul><h2 id="当前范围之外" tabindex="-1">当前范围之外 <a class="header-anchor" href="#当前范围之外" aria-label="Permalink to &quot;当前范围之外&quot;">​</a></h2><p>这一阶段还没有：</p><ul><li>用户账号</li><li>团队登录</li><li>Key scope</li><li>Key 过期时间</li><li>按 Key 限流</li></ul><p>这些属于后续安全增强，不是第一阶段自托管局域网可用性的前置条件。</p>',27)])])}const u=e(s,[["render",o]]);export{k as __pageData,u as default};
